examples.code:
#include <iostream>
using namespace std;
int main() {
    for (int i = 1; i <= 5; i++) {
        cout << i << endl;
    }

    // Sum with accumulator:
    int sum = 0;
    for (int i = 1; i <= 10; i++) {
        sum += i;
    }
    cout << sum << endl; // 55
    return 0;
}

// auto deduces int here:
for (auto i = 0; i < 5; i++) {
    cout << i << endl;
}

// More useful with complex types:
vector<int> v = {1,2,3,4,5};
for (auto i = 0; i < v.size(); i++) {
    cout << v[i] << endl;
}

#include <vector>
#include <string>
using namespace std;

// With raw array:
int arr[] = {10, 20, 30, 40};
for (auto x : arr) {
    cout << x << endl;
}

// With vector:
vector<int> v = {1,2,3,4,5};
for (const auto& n : v) {  // const ref — no copy!
    cout << n << endl;
}

// String chars:
string s = "hello";
for (char c : s) {
    cout << c << " ";
}
// h e l l o

vector<int> nums = {1, 2, 3, 4, 5};

// auto& allows modification:
for (auto& n : nums) {
    n *= 2;  // doubles each element
}

for (const auto& n : nums) {
    cout << n << " ";  // 2 4 6 8 10
}

