// break:
for (int i = 0; i < 10; i++) {
    if (i == 5) break;
    cout << i << " ";
}
// 0 1 2 3 4

// continue — skip evens:
for (int i = 0; i < 8; i++) {
    if (i % 2 == 0) continue;
    cout << i << " ";
}
// 1 3 5 7

#include <algorithm>
vector<int> v = {3,7,1,9,4};

// Find first > 5 (replaces loop + break):
auto it = find_if(v.begin(),v.end(),[](int x){return x>5;});
if (it != v.end()) cout << *it << endl; // 7

// Check any > 8:
bool any = any_of(v.begin(),v.end(),[](int x){return x>8;});
cout << boolalpha << any << endl; // true (9>8)

